(window.webpackJsonp=window.webpackJsonp||[]).push([[20],{647:function(n,r){n.exports='\x3c!-- \r\ntitle: 02-CSharp基础语法\r\nsort: \r\n--\x3e \r\n\r\n## 数据类型\r\n\r\n> 与c++差不多\r\n\r\n- sizeof\r\n\r\n  `Console.WriteLine("Size of int: {0}", sizeof(int));`\r\n\r\n### 引用类型\r\n\r\n#### 对象类型\r\n\r\n```c#\r\n// Object是c#的基类,可以转换后分配给任何类型\r\nint val=404;\r\nobject objtest = val;\r\nobjtest = 4042;\r\nConsole.WriteLine(objtest);\r\n// 4042\r\n```\r\n\r\n#### 动态类型`dynamic`\r\n\r\n> 对象类型的变量编译时进行类型检查,动态类型在运行时检查.\r\n\r\n```c#\r\ndynamic vars="dynamic test!";\r\nConsole.WriteLine(vars);\r\n```\r\n\r\n#### 字符串类型\r\n\r\n```c#\r\nString str = "hello\\tfzf!";\r\nString stra = @"hello\r\n\t\t\t\t\\tfzf";\r\nConsole.WriteLine("Str: {0}\\n@Str: {1}", str, stra);\r\n// Str: hello\tfzf!\r\n// @Str: hello\\\r\n//\t\t\t\t\\tfzf\r\n```\r\n\r\n#### 指针类型\r\n\r\n> 与c中的指针具有相同功能\r\n\r\n### 类型转换\r\n\r\n```c#\r\ndouble d = 3.1415;\r\nint i;\r\n// 转换\r\ni = (int)d;\r\nstring str = d.ToString();\r\n```\r\n\r\n## 接收用户输入\r\n\r\n```c#\r\nnum = Convert.ToInt32(Console.ReadLine());\r\nConsole.WriteLine("Input num is: {0}", num);\r\n```\r\n\r\n\r\n\r\n\r\n\r\n'}}]);